// N3-26 V5: 出品実行 - 鉄の掟準拠
const apiUrl = $env.N3_API_URL || $env.API_BASE_URL;
if (!apiUrl) return [{ json: { error: true, message: 'N3_API_URL未設定', code: 'CONFIG_ERROR' } }];

const body = $input.first().json.body || $input.first().json || {};

const productId = body.product_id;
const marketplace = body.marketplace || 'ebay'; // ebay, qoo10, shopify, amazon
const account = body.account || 'default';
const listingMode = body.listing_mode || 'standard'; // standard, auction, bulk
const scheduledAt = body.scheduled_at;
const priority = body.priority || 'normal';

if (!productId) return [{ json: { error: true, message: 'product_id必須', code: 'MISSING_PARAM' } }];

return [{ json: { product_id: productId, marketplace, account, listing_mode: listingMode, scheduled_at: scheduledAt, priority, api_url: apiUrl, timestamp: new Date().toISOString() } }];

const init = $node['🔐 初期化（鉄の掟）'].json;
const product = $input.first().json;

if (!product || !product.id) return [{ json: { ...init, error: true, message: '商品が見つかりません' } }];
if (product.inv_status === 'out_of_stock') return [{ json: { ...init, error: true, message: '在庫切れのため出品不可' } }];
if (!product.title_en) return [{ json: { ...init, error: true, message: '英語タイトル未設定' } }];

return [{ json: { ...init, product, ready_to_list: true } }];

const data = $input.first().json;
const mp = data.marketplace;

// マーケットプレイス別のWebhookパスを決定
const webhookPaths = {
  ebay: '/webhook/ebay-listing',
  qoo10: '/webhook/qoo10-listing',
  shopify: '/webhook/shopify-listing',
  amazon: '/webhook/amazon-listing',
  shopee: '/webhook/shopee-listing',
  lazada: '/webhook/lazada-listing'
};

const webhookPath = webhookPaths[mp] || webhookPaths.ebay;

return [{ json: { ...data, webhook_path: webhookPath, target_url: data.api_url + webhookPath } }];

const result = $input.first().json;
const prevData = $node['🔀 販路ルーティング'].json;

const success = result.success !== false && !result.error;
const listingId = result.listing_id || result.item_id || result.ebay_item_id;

return [{ json: { ...prevData, listing_result: { success, listing_id: listingId, error: result.error || result.message, raw: result } } }];

const d = $input.first().json;
const result = d.listing_result || {};
return [{ json: { success: result.success || false, action: 'listing_executed', product_id: d.product_id, marketplace: d.marketplace, account: d.account, listing_id: result.listing_id, error: result.error, timestamp: new Date().toISOString() } }];

// 🔐 HMAC SHA256 署名検証 (Empire OS v6)
const crypto = require('crypto');

const signature = $request.headers['x-n3-signature'] || $request.headers['X-N3-Signature'];
const timestamp = $request.headers['x-n3-timestamp'] || $request.headers['X-N3-Timestamp'];
const secret = $env.N8N_HMAC_SECRET;

if (!secret) {
  throw new Error('🚫 N8N_HMAC_SECRET 環境変数が未設定です');
}

if (!signature || !timestamp) {
  throw new Error('🚫 署名またはタイムスタンプが欠落しています');
}

// タイムスタンプ有効期限チェック (5分)
const now = Date.now();
const tsAge = now - parseInt(timestamp);
if (tsAge > 300000 || tsAge < -30000) {
  throw new Error('🚫 タイムスタンプが期限切れまたは不正です');
}

// HMAC検証
const bodyString = JSON.stringify($json);
const computedHmac = crypto
  .createHmac('sha256', secret)
  .update(timestamp + '.' + bodyString)
  .digest('hex');

if (signature !== computedHmac) {
  throw new Error('🚫 HMAC署名検証失敗: 不正なリクエスト');
}

// 検証成功 - 元データをそのまま返す
return [{ json: $json }];
